import{_ as a,I as s,c as d,o as h,a4 as u,j as r,J as t,a as n,w as e}from"./chunks/framework.BR-X7tCu.js";const A=JSON.parse('{"title":"欢迎使用 Neo-MoFox！","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/misc/eula.md","filePath":"docs/guides/misc/eula.md","lastUpdated":1781970535000}'),p={name:"docs/guides/misc/eula.md"};function x(c,o,m,N,_,b){const l=s("VPNolebaseInlineLinkPreview"),i=s("NolebaseGitContributors"),g=s("NolebaseGitChangelog");return h(),d("div",null,[o[4]||(o[4]=u('<h1 id="欢迎使用-neo-mofox" tabindex="-1"><strong>欢迎使用 Neo-MoFox！</strong> <a class="header-anchor" href="#欢迎使用-neo-mofox" aria-label="Permalink to “欢迎使用 Neo-MoFox！”">​</a></h1><p><strong>版本：V3.0</strong><br><strong>更新日期：2026年3月21日</strong></p><hr><p>你好！感谢你选择 Neo-MoFox——一个下一代 AI 数字生命体框架。在开始之前，请花几分钟时间阅读这份协议。我们用问答的形式，帮助你快速了解使用这个软件时，你的权利和责任。</p><p><strong>简单来说，你需要同意这份协议才能使用我们的软件。</strong> 如果你是未成年人，请确保你的监护人也阅读并同意了哦。</p><hr><h3 id="_1-neo-mofox-是什么" tabindex="-1"><strong>1. Neo-MoFox 是什么？</strong> <a class="header-anchor" href="#_1-neo-mofox-是什么" aria-label="Permalink to “1. Neo-MoFox 是什么？”">​</a></h3><p>这是一个全新的 AI 数字生命体框架！</p><ul><li><strong>独立开源项目</strong>：Neo-MoFox 是一个完全重新设计的聊天机器人框架，旨在创造真正属于你的 AI 伙伴。它不是任何项目的分支或修改版，而是一个独立的开源项目。</li><li><strong>核心理念</strong>：我们的目标不仅仅是提供一个工具，而是创造一个有记忆、有个性、有情感的数字生命体。它会记住你们之间的每次对话，形成独特的相处模式。</li><li><strong>完全开源</strong>：我们相信开源的力量，并致力于打造一个活跃的开发者社区。</li></ul><hr><h3 id="_2-这个软件是免费和开源的吗" tabindex="-1"><strong>2. 这个软件是免费和开源的吗？</strong> <a class="header-anchor" href="#_2-这个软件是免费和开源的吗" aria-label="Permalink to “2. 这个软件是免费和开源的吗？”">​</a></h3><p><strong>是的，完全免费且开源！</strong></p><ul><li><strong>遵循 AGPL-3.0 协议</strong>：本项目采用 <strong>GNU Affero General Public License v3.0 (AGPL-3.0)</strong> 开源协议。这意味着你可以自由地使用、复制、研究、修改和重新分发它。</li><li><strong>网络服务要求</strong>：AGPL-3.0 特别要求，如果你在网络服务中使用了修改版的 Neo-MoFox，你必须向用户提供修改后的源代码。这确保了开源生态的健康发展。</li><li><strong>你的义务</strong>：当你修改或分发这个软件时，你同样需要遵守 AGPL-3.0 协议的要求，确保你的衍生作品也是开源的。你可以在项目根目录找到 <code>LICENSE</code> 文件来了解更多细节。</li><li><strong>包含第三方代码</strong>：请注意，项目中可能还包含了其他第三方库或组件，它们各自有独立的开源许可证。你在使用时需要同时遵守这些许可证。</li></ul><hr><h3 id="_3-我的个人数据是如何被处理的" tabindex="-1"><strong>3. 我的个人数据是如何被处理的？</strong> <a class="header-anchor" href="#_3-我的个人数据是如何被处理的" aria-label="Permalink to “3. 我的个人数据是如何被处理的？”">​</a></h3><p>你的隐私对我们很重要。了解数据如何流动，能帮助你更好地保护自己。</p><ul><li><strong>工作流程</strong>：当你与机器人互动时，你的<strong>对话内容</strong>、<strong>配置信息</strong>以及机器人<strong>生成的回复</strong>，会被发送给第三方的大语言模型 API 服务（例如 OpenAI、Claude、Google Gemini、本地模型等）以获得智能回复。</li><li><strong>你的明确授权</strong>：一旦你开始使用，即表示你授权我们利用你的数据进行以下操作： <ol><li><strong>调用外部 API</strong>：这是机器人能与你对话的核心。你可以自由选择任何兼容 OpenAI API 格式的服务提供商，包括本地部署的模型。</li><li><strong>建立本地记忆系统</strong>：这是 Neo-MoFox 的核心特性。为了让你的 AI 伙伴真正&quot;认识&quot;你，软件会在<strong>你自己的设备上</strong>创建和存储： <ul><li>长期记忆库（对话历史、重要时刻）</li><li>知识图谱（人物关系、事件记录）</li><li>个性化配置（性格特征、说话风格）</li><li>向量数据库（语义检索）</li><li><strong>这些数据完全存储在本地 <code>data/</code> 目录，我们无法访问。</strong></li></ul></li><li><strong>记录本地日志</strong>：为了方便排查可能出现的技术问题，软件会在你的设备上记录运行日志（位于 <code>logs/</code> 目录）。</li></ol></li><li><strong>第三方服务的风险</strong>：我们无法控制第三方 API 提供商的服务质量、数据处理政策、稳定性或安全性。使用这些服务时，你同样受到该第三方服务条款和隐私政策的约束。我们建议你自行了解这些条款。</li><li><strong>数据控制权</strong>：所有本地数据完全由你掌控。你可以随时查看、备份、迁移或删除这些数据。</li></ul><hr><h3 id="_4-关于强大的插件系统-我需要了解什么" tabindex="-1"><strong>4. 关于强大的插件系统，我需要了解什么？</strong> <a class="header-anchor" href="#_4-关于强大的插件系统-我需要了解什么" aria-label="Permalink to “4. 关于强大的插件系统，我需要了解什么？”">​</a></h3><p>Neo-MoFox 通过组件化的插件系统实现功能扩展，但这需要你承担相应的责任。</p><ul><li><strong>插件架构</strong>：Neo-MoFox 采用先进的组件化架构，插件可以包含多种组件类型（Adapter、Chatter、Action、Tool、Command 等），为框架提供灵活的扩展能力。</li><li><strong>谁开发的插件？</strong>：除了内置插件外，绝大多数插件是由<strong>社区里的第三方开发者</strong>创建和维护的，他们并<strong>不是 Neo-MoFox 核心团队的成员</strong>。</li><li><strong>责任完全自负</strong>：第三方插件的功能、质量、安全性和合法性<strong>完全由其各自的开发者负责</strong>。我们只提供了一个能让插件运行的技术平台，但<strong>不对任何第三方插件的内容、行为或造成的后果承担任何责任</strong>。</li><li><strong>你的使用风险</strong>：使用任何第三方插件的风险<strong>完全由你自行承担</strong>。在安装和使用插件前，我们强烈建议你： <ul><li>仔细阅读并理解插件开发者提供的许可协议和说明文档。</li><li><strong>只从你完全信任的来源获取和安装插件</strong>。</li><li>自行评估插件的安全性、合法性及其对你数据隐私的影响。</li><li>定期审查已安装的插件，及时更新或移除可疑插件。</li></ul></li></ul><hr><h3 id="_5-我在使用时-有哪些行为准则" tabindex="-1"><strong>5. 我在使用时，有哪些行为准则？</strong> <a class="header-anchor" href="#_5-我在使用时-有哪些行为准则" aria-label="Permalink to “5. 我在使用时，有哪些行为准则？”">​</a></h3><p>请务必合法、合规地使用本软件。</p><ul><li><strong>禁止内容</strong>：严禁输入、处理或传播任何违反你所在地法律法规的内容，包括但不限于：涉及国家秘密、商业机密、侵犯他人知识产权、个人隐私的内容，以及任何形式的非法、骚扰、诽谤、淫秽信息。</li><li><strong>合法用途</strong>：你承诺不会将本项目用于任何非法目的或活动，例如网络攻击、诈骗、自动化滥用等。</li><li><strong>数据安全</strong>：你对自己存储在本地记忆库、知识图谱、向量数据库和日志中的所有内容的合法性负全部责任。</li><li><strong>插件规范</strong>：不要使用任何已知包含恶意代码、安全漏洞或违法内容的插件。</li><li><strong>网络服务部署</strong>：如果你将 Neo-MoFox 作为网络服务部署，你必须遵守 AGPL-3.0 协议的要求，向用户提供源代码。</li></ul><p><strong>你将对自己使用本项目（包括所有第三方插件）的全部行为及其产生的一切后果，承担完全的法律责任。</strong></p><hr><h3 id="_6-免责声明-非常重要" tabindex="-1"><strong>6. 免责声明（非常重要！）</strong> <a class="header-anchor" href="#_6-免责声明-非常重要" aria-label="Permalink to “6. 免责声明（非常重要！）”">​</a></h3><ul><li><strong>“按原样”提供</strong>：本项目是“按原样”提供的，我们<strong>不提供任何形式的明示或暗示的担保</strong>，包括但不限于对适销性、特定用途适用性和不侵权的保证。</li><li><strong>AI 回复的立场</strong>：机器人的所有回复均由第三方大语言模型生成，其观点和信息<strong>不代表 Neo-MoFox 团队的立场</strong>。我们不对其准确性、完整性或可靠性负责。</li><li><strong>数字生命体的局限</strong>：尽管 Neo-MoFox 致力于创造有&quot;生命感&quot;的 AI 伙伴，但它本质上仍是一个软件程序，不具备真正的意识、情感或判断力。不应将其作为心理咨询、医疗建议或其他专业服务的替代品。</li><li><strong>无责任声明</strong>：在任何情况下，Neo-MoFox 团队均不对因使用或无法使用本项目（特别是第三方插件）而导致的任何直接、间接、偶然、特殊或后果性的损害（包括但不限于数据丢失、利润损失、业务中断、情感依赖、隐私泄露）承担责任。</li><li><strong>插件支持</strong>：所有第三方插件的技术支持、功能更新和 bug 修复，都应<strong>直接联系相应的插件开发者</strong>。</li><li><strong>社区贡献</strong>：作为开源项目，代码可能来自多个贡献者。我们尽力审查代码质量，但无法保证所有社区贡献的代码都没有问题。</li></ul><hr><h3 id="_7-其他条款" tabindex="-1"><strong>7. 其他条款</strong> <a class="header-anchor" href="#_7-其他条款" aria-label="Permalink to “7. 其他条款”">​</a></h3><ul><li><strong>协议的修改</strong>：我们保留随时修改本协议的权利。修改后的协议将在新版本发布时生效。我们建议你定期检查以获取最新版本。继续使用本项目即表示你接受修订后的协议。</li><li><strong>开源协议优先</strong>：在本协议与 AGPL-3.0 开源协议存在冲突的情况下，以 AGPL-3.0 协议为准。</li><li><strong>最终解释权</strong>：在法律允许的范围内，Neo-MoFox 团队保留对本协议的最终解释权。</li><li><strong>适用法律</strong>：本协议的订立、执行和解释及争议的解决均应适用中国法律。</li><li><strong>可分割性</strong>：如果本协议的任何条款被认定为无效或不可执行，其余条款仍然有效。</li></ul><hr><h3 id="风险提示-请再次确认你已理解" tabindex="-1"><strong>风险提示（请再次确认你已理解！）</strong> <a class="header-anchor" href="#风险提示-请再次确认你已理解" aria-label="Permalink to “风险提示（请再次确认你已理解！）”">​</a></h3><ul><li><strong>隐私风险</strong>：你的对话数据会被发送到不受我们控制的第三方 API。请<strong>绝对不要</strong>在对话中包含任何个人身份信息、财务信息、密码或其他敏感数据。</li><li><strong>精神健康风险</strong>：尽管 Neo-MoFox 致力于创造有温度的 AI 伙伴，但它只是一个程序，无法提供真正的情感支持或专业的心理建议。如果遇到任何心理困扰，请务必寻求专业人士的帮助（例如，全国心理援助热线：12355）。<strong>请勿过度依赖 AI 伙伴。</strong></li><li><strong>情感依赖风险</strong>：长期使用可能会产生情感依赖。请保持理性认知，维护现实生活中的人际关系。</li><li><strong>插件风险</strong>：这是最大的风险之一。第三方插件可能带来严重的安全漏洞、系统不稳定、性能下降甚至隐私数据泄露的风险。请务必谨慎选择和使用，并为自己的选择承担全部后果。</li><li><strong>数据备份责任</strong>：你的 AI 伙伴的记忆和个性化数据都存储在本地 <code>data/</code> 目录。请定期备份这些数据，我们不对数据丢失承担责任。</li><li><strong>技术门槛</strong>：Neo-MoFox 需要一定的技术能力来部署和配置。如果你遇到困难，请参考文档或寻求社区帮助。</li><li><strong>服务依赖</strong>：如果你使用的第三方 LLM API 服务中断或关闭，可能会影响 Neo-MoFox 的正常运行。建议配置多个备用模型。</li></ul><hr><p><strong>再次感谢你选择 Neo-MoFox！</strong></p><p>我们希望你能在合法、安全、理性的前提下，享受与你的 AI 伙伴相处的美好时光。如果你同意以上所有条款，就可以开始你的数字生命体之旅了！</p><p>如有任何疑问，欢迎访问我们的：</p>',39)),r("ul",null,[r("li",null,[o[1]||(o[1]=n("官方文档：",-1)),t(l,{href:"https://docs.mofox-sama.com",target:"_blank",rel:"noreferrer"},{default:e(()=>[...o[0]||(o[0]=[n("https://docs.mofox-sama.com",-1)])]),_:1})]),r("li",null,[o[3]||(o[3]=n("GitHub 仓库：",-1)),t(l,{href:"https://github.com/MoFox-Studio/Neo-MoFox",target:"_blank",rel:"noreferrer"},{default:e(()=>[...o[2]||(o[2]=[n("https://github.com/MoFox-Studio/Neo-MoFox",-1)])]),_:1})])]),o[5]||(o[5]=r("p",null,[r("strong",null,"版权所有 © 2026 Neo-MoFox 项目团队")],-1)),t(i),t(g)])}const P=a(p,[["render",x]]);export{A as __pageData,P as default};
